parameters.jsCode:
const event = $('Normalizar Evento').first().json;
const content = $json.choices?.[0]?.message?.content || '{}';
let ai = {};

try {
  ai = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  ai = { shouldTrigger: true, trigger: event.trigger, targetId: event.targetId, targetLabel: event.targetLabel, reason: 'Fallback: IA retornou JSON inválido.' };
}

if (ai.shouldTrigger === false) {
  return [{ json: { skipped: true, reason: ai.reason || 'IA bloqueou o disparo.', event } }];
}

return [{
  json: {
    skipped: false,
    trigger: ai.trigger || event.trigger,
    targetId: ai.targetId || event.targetId,
    targetLabel: ai.targetLabel || event.targetLabel,
    contactId: event.contactId,
    contactAirtableId: event.contactAirtableId,
    chatId: event.chatId,
    contactName: event.contactName,
    contactPhone: event.contactPhone,
    occurredAt: event.occurredAt,
    aiReason: ai.reason || '',
    raw: event.raw
  }
}];
